{
"title": "ऑरोरा फेलओवर तंत्र",
  "group": "ऑरोरा उच्च उपलब्धता",
  "options": [
    {
      "text": "हस्तचालित हस्तक्षेप आवश्यक"
    },
    {
      "text": "एप्लिकेशन पुन:कॉन्फ़िगरेशन की आवश्यकता"
    },
    {
      "text": "हमेशा सबसे पुराने रेप्लिका पर फेलओवर करता है"
    },
    {
      "text": "फेलओवर प्राथमिकता स्तर के आधार पर स्वचालित प्रोमोशन"
    }
  ],
  "questionProse": [
    "एक ऑरोरा क्लस्टर में कई रीड रेप्लिकाओं के साथ, जब प्राथमिक इंस्टेंस फेल हो जाता है तो स्वचालित फेलओवर के दौरान क्या होता है?"
  ],
  "explanationProse": [
    "ऑरोरा फेलओवर प्रक्रिया:\n      1. प्राथमिक इंस्टेंस विफलता का पता लगाता है\n      2. फेलओवर प्राथमिकता स्तर के आधार पर मुख्य रूप से एक ऑरोरा रेप्लिका चुनता है\n      3. जब प्राथमिकताएँ समान हों तो टाई‑ब्रेकर के रूप में इंस्टेंस विशेषताओं का उपयोग करता है\n      4. क्लस्टर एंडपॉइंट को स्वचालित रूप से अपडेट करता है\n\n      सर्वोत्तम प्रथाएँ:\n      - विभिन्न AZs में कई रेप्लिकाएँ बनाए रखें\n      - प्रोमोशन टियर्स को जानबूझकर कॉन्फ़िगर करें\n      - एप्लिकेशनों में क्लस्टर एंडपॉइंट का उपयोग करें\n      - फेलओवर परिदृश्यों का नियमित रूप से परीक्षण करें"
  ]
}
